<template>
  <div class="product-statistics-container">
    <el-card class="filter-container">
      <div slot="header" class="clearfix">
        <span>商品分析</span>
      </div>
      
      <el-form :inline="true" :model="filterForm" class="filter-form">
        <el-form-item label="时间范围">
          <el-date-picker
            v-model="filterForm.dateRange"
            type="daterange"
            range-separator="至"
            start-placeholder="开始日期"
            end-placeholder="结束日期"
            value-format="yyyy-MM-dd"
            :picker-options="pickerOptions">
          </el-date-picker>
        </el-form-item>
        <el-form-item label="分类">
          <el-select v-model="filterForm.categoryId" placeholder="全部分类" clearable>
            <el-option
              v-for="item in categoryOptions"
              :key="item.value"
              :label="item.label"
              :value="item.value">
            </el-option>
          </el-select>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="fetchData">查询</el-button>
          <el-button @click="exportData" icon="el-icon-download">导出</el-button>
        </el-form-item>
      </el-form>
    </el-card>
    
    <el-row :gutter="20" class="stat-cards">
      <el-col :span="6" v-for="(stat, index) in statCards" :key="index">
        <el-card shadow="hover" class="stat-card">
          <div class="stat-card-value">{{ stat.value }}</div>
          <div class="stat-card-title">{{ stat.title }}</div>
          <div class="stat-card-change" :class="stat.change >= 0 ? 'positive' : 'negative'">
            <i :class="stat.change >= 0 ? 'el-icon-top' : 'el-icon-bottom'"></i>
            {{ Math.abs(stat.change) }}% 较上期
          </div>
        </el-card>
      </el-col>
    </el-row>
    
    <el-row :gutter="20" class="chart-row">
      <el-col :span="12">
        <el-card class="chart-card">
          <div slot="header" class="clearfix">
            <span>热销商品排行</span>
            <el-select v-model="topProductsType" size="mini" style="float: right; width: 120px;" @change="switchTopProductsType">
              <el-option label="按销量" value="quantity"></el-option>
              <el-option label="按销售额" value="amount"></el-option>
            </el-select>
          </div>
          <div id="topProductsChart" style="width: 100%; height: 350px;"></div>
        </el-card>
      </el-col>
      <el-col :span="12">
        <el-card class="chart-card">
          <div slot="header" class="clearfix">
            <span>商品分类销售占比</span>
          </div>
          <div id="categorySalesChart" style="width: 100%; height: 350px;"></div>
        </el-card>
      </el-col>
    </el-row>
    
    <el-card class="table-card">
      <div slot="header" class="clearfix">
        <span>商品销售详情</span>
        <div class="header-operations">
          <el-input
            placeholder="输入商品名称搜索"
            v-model="searchKeyword"
            clearable
            prefix-icon="el-icon-search"
            style="width: 200px; margin-right: 10px;"
            @keyup.enter.native="handleSearch"
            @clear="handleSearch">
          </el-input>
          <el-select v-model="sortBy" placeholder="排序方式" style="width: 120px;" @change="handleSort">
            <el-option label="销量高到低" value="quantityDesc"></el-option>
            <el-option label="销量低到高" value="quantityAsc"></el-option>
            <el-option label="销售额高到低" value="amountDesc"></el-option>
            <el-option label="销售额低到高" value="amountAsc"></el-option>
          </el-select>
        </div>
      </div>
      
      <el-table
        :data="productList"
        style="width: 100%"
        border
        v-loading="loading">
        <el-table-column
          prop="id"
          label="商品ID"
          width="90">
        </el-table-column>
        <el-table-column
          label="商品"
          width="300">
          <template slot-scope="scope">
            <div class="product-info">
              <img :src="scope.row.image" class="product-image">
              <div class="product-details">
                <div class="product-name">{{ scope.row.name }}</div>
                <div class="product-category">{{ scope.row.categoryName }}</div>
              </div>
            </div>
          </template>
        </el-table-column>
        <el-table-column
          prop="price"
          label="单价"
          width="110">
          <template slot-scope="scope">
            ¥ {{ formatNumber(scope.row.price) }}
          </template>
        </el-table-column>
        <el-table-column
          prop="soldQuantity"
          label="销量"
          sortable
          width="100">
        </el-table-column>
        <el-table-column
          prop="salesAmount"
          label="销售额"
          sortable
          width="150">
          <template slot-scope="scope">
            ¥ {{ formatNumber(scope.row.salesAmount) }}
          </template>
        </el-table-column>
        <el-table-column
          prop="refundQuantity"
          label="退款数量"
          width="120">
        </el-table-column>
        <el-table-column
          prop="refundRate"
          label="退款率"
          width="120">
          <template slot-scope="scope">
            {{ scope.row.refundRate }}%
          </template>
        </el-table-column>
        <el-table-column
          prop="visitCount"
          label="浏览量"
          width="120">
        </el-table-column>
        <el-table-column
          prop="conversionRate"
          label="转化率"
          width="120">
          <template slot-scope="scope">
            {{ scope.row.conversionRate }}%
          </template>
        </el-table-column>
        <el-table-column
          label="操作"
          width="100"
          fixed="right">
          <template slot-scope="scope">
            <el-button @click="viewProductDetails(scope.row.id)" type="text" size="small">查看详情</el-button>
          </template>
        </el-table-column>
      </el-table>
      <el-empty v-if="!loading && productList.length === 0" description="暂无数据" />
      
      <div class="pagination-container">
        <el-pagination
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="pagination.currentPage"
          :page-sizes="[10, 20, 50, 100]"
          :page-size="pagination.pageSize"
          layout="total, sizes, prev, pager, next, jumper"
          :total="pagination.total">
        </el-pagination>
      </div>
    </el-card>
    
    <!-- 商品详情对话框 -->
    <el-dialog title="商品销售详情" :visible.sync="dialogVisible" width="70%">
      <el-descriptions :column="2" border>
        <el-descriptions-item label="商品名称">{{ currentProduct.name }}</el-descriptions-item>
        <el-descriptions-item label="所属分类">{{ currentProduct.categoryName }}</el-descriptions-item>
        <el-descriptions-item label="单价">¥ {{ formatNumber(currentProduct.price) }}</el-descriptions-item>
        <el-descriptions-item label="销量">{{ currentProduct.soldQuantity }}</el-descriptions-item>
        <el-descriptions-item label="销售额">¥ {{ formatNumber(currentProduct.salesAmount) }}</el-descriptions-item>
        <el-descriptions-item label="浏览量">{{ currentProduct.visitCount }}</el-descriptions-item>
        <el-descriptions-item label="转化率">{{ currentProduct.conversionRate }}%</el-descriptions-item>
        <el-descriptions-item label="平均评分">{{ currentProduct.averageRating }} <el-rate v-model="currentProduct.averageRating" disabled text-color="#ff9900"></el-rate></el-descriptions-item>
      </el-descriptions>
      
      <el-divider content-position="left">销售趋势</el-divider>
      <div id="productDetailChart" style="width: 100%; height: 300px;"></div>
      
      <el-divider content-position="left">客户评价</el-divider>
      <el-table :data="currentProduct.reviews" style="width: 100%">
        <el-table-column prop="username" label="客户" width="180"></el-table-column>
        <el-table-column prop="rating" label="评分" width="120">
          <template slot-scope="scope">
            <el-rate v-model="scope.row.rating" disabled></el-rate>
          </template>
        </el-table-column>
        <el-table-column prop="content" label="评价内容"></el-table-column>
        <el-table-column prop="createTime" label="评价时间" width="180"></el-table-column>
      </el-table>
      
      <span slot="footer" class="dialog-footer">
        <el-button @click="dialogVisible = false">关闭</el-button>
        <el-button type="primary" @click="goToProductEdit">编辑商品</el-button>
      </span>
    </el-dialog>
  </div>
</template>

<script>
import * as echarts from 'echarts'
import statisticsApi from '@/api/statistics'

export default {
  name: 'ProductStatistics',
  data() {
    return {
      filterForm: {
        dateRange: [this.getLastMonthDate(), this.formatDate(new Date())],
        categoryId: ''
      },
      pickerOptions: {
        shortcuts: [
          {
            text: '最近一周',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24 * 7)
              picker.$emit('pick', [start, end])
            }
          },
          {
            text: '最近一个月',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24 * 30)
              picker.$emit('pick', [start, end])
            }
          },
          {
            text: '最近三个月',
            onClick(picker) {
              const end = new Date()
              const start = new Date()
              start.setTime(start.getTime() - 3600 * 1000 * 24 * 90)
              picker.$emit('pick', [start, end])
            }
          }
        ]
      },
      categoryOptions: [],
      statCards: [
        { title: '商品总销量', value: '0', change: 0 },
        { title: '商品总销售额', value: '¥0.00', change: 0 },
        { title: '平均转化率', value: '0%', change: 0 },
        { title: '平均退款率', value: '0%', change: 0 }
      ],
      topProductsType: 'quantity',
      sortBy: 'quantityDesc',
      searchKeyword: '',
      productList: [],
      loading: false,
      topProductsChart: null,
      categorySalesChart: null,
      productDetailChart: null,
      dialogVisible: false,
      currentProduct: {
        id: '',
        name: '',
        categoryName: '',
        price: 0,
        soldQuantity: 0,
        salesAmount: 0,
        visitCount: 0,
        conversionRate: 0,
        averageRating: 0,
        reviews: []
      },
      pagination: {
        currentPage: 1,
        pageSize: 10,
        total: 0
      }
    }
  },
  mounted() {
    this.fetchCategoryOptions()
    this.fetchData()
    window.addEventListener('resize', this.resizeCharts)
  },
  beforeDestroy() {
    window.removeEventListener('resize', this.resizeCharts)
    this.disposeCharts()
  },
  methods: {
    formatDate(date) {
      const year = date.getFullYear()
      const month = String(date.getMonth() + 1).padStart(2, '0')
      const day = String(date.getDate()).padStart(2, '0')
      return `${year}-${month}-${day}`
    },
    getLastMonthDate() {
      const date = new Date()
      date.setMonth(date.getMonth() - 1)
      return this.formatDate(date)
    },
    formatNumber(num) {
      if (num === undefined || num === null) return '0.00'
      return num.toLocaleString('zh-CN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })
    },
    async fetchCategoryOptions() {
      try {
        const response = await statisticsApi.getCategorySales()
        if (response.code === 0 && response.data) {
          this.categoryOptions = response.data.map(category => ({
            value: category.id,
            label: category.name
          }))
        }
      } catch (error) {
        console.error('获取分类选项出错:', error)
      }
    },
    async fetchData() {
      this.loading = true
      try {
        const params = {
          startDate: this.filterForm.dateRange[0],
          endDate: this.filterForm.dateRange[1],
          categoryId: this.filterForm.categoryId,
          page: this.pagination.currentPage,
          pageSize: this.pagination.pageSize,
          sort: this.sortBy,
          keyword: this.searchKeyword
        }
        
        const response = await statisticsApi.getSales(params)
        
        if (response.code === 0 && response.data) {
          // 更新统计卡片数据
          this.updateStatCards(response.data.overview)
          
          // 更新商品列表
          this.productList = response.data.products.list
          this.pagination.total = response.data.products.total
          
          // 初始化图表
          this.initTopProductsChart(response.data.topProducts)
          this.initCategorySalesChart(response.data.categoryDistribution)
        } else {
          this.$message.error(response.message || '获取商品统计数据失败')
        }
      } catch (error) {
        console.error('获取商品统计数据出错:', error)
        this.$message.error('获取商品统计数据出错')
      } finally {
        this.loading = false
      }
    },
    updateStatCards(overview) {
      if (!overview) return
      
      this.statCards[0].value = overview.totalSoldQuantity.toLocaleString()
      this.statCards[0].change = overview.soldQuantityGrowth
      
      this.statCards[1].value = '¥' + this.formatNumber(overview.totalSalesAmount)
      this.statCards[1].change = overview.salesAmountGrowth
      
      this.statCards[2].value = overview.averageConversionRate + '%'
      this.statCards[2].change = overview.conversionRateGrowth
      
      this.statCards[3].value = overview.averageRefundRate + '%'
      this.statCards[3].change = -overview.refundRateGrowth // 负增长是好事
    },
    initTopProductsChart(data) {
      if (!data) return
      
      if (!this.topProductsChart) {
        this.topProductsChart = echarts.init(document.getElementById('topProductsChart'))
      }
      
      const option = {
        tooltip: {
          trigger: 'axis',
          axisPointer: {
            type: 'shadow'
          }
        },
        grid: {
          left: '3%',
          right: '4%',
          bottom: '3%',
          containLabel: true
        },
        xAxis: {
          type: 'value',
          name: this.topProductsType === 'quantity' ? '销量(件)' : '销售额(元)'
        },
        yAxis: {
          type: 'category',
          data: data.map(item => item.name),
          axisLabel: {
            width: 120,
            overflow: 'truncate'
          }
        },
        series: [
          {
            name: this.topProductsType === 'quantity' ? '销量' : '销售额',
            type: 'bar',
            data: data.map(item => this.topProductsType === 'quantity' ? item.soldQuantity : item.salesAmount),
            itemStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 1, 0, [
                { offset: 0, color: '#83bff6' },
                { offset: 0.5, color: '#188df0' },
                { offset: 1, color: '#188df0' }
              ])
            }
          }
        ]
      }
      
      this.topProductsChart.setOption(option)
    },
    initCategorySalesChart(data) {
      if (!data) return
      
      if (!this.categorySalesChart) {
        this.categorySalesChart = echarts.init(document.getElementById('categorySalesChart'))
      }
      
      const option = {
        tooltip: {
          trigger: 'item',
          formatter: '{a} <br/>{b} : {c} ({d}%)'
        },
        legend: {
          orient: 'vertical',
          left: 'left',
          data: data.map(item => item.name)
        },
        series: [
          {
            name: '分类销售额',
            type: 'pie',
            radius: '55%',
            center: ['50%', '60%'],
            data: data.map(item => ({
              value: item.salesAmount,
              name: item.name
            })),
            emphasis: {
              itemStyle: {
                shadowBlur: 10,
                shadowOffsetX: 0,
                shadowColor: 'rgba(0, 0, 0, 0.5)'
              }
            }
          }
        ]
      }
      
      this.categorySalesChart.setOption(option)
    },
    initProductDetailChart(data) {
      if (!data) return
      
      if (!this.productDetailChart) {
        this.productDetailChart = echarts.init(document.getElementById('productDetailChart'))
      }
      
      const option = {
        tooltip: {
          trigger: 'axis'
        },
        legend: {
          data: ['销量', '销售额', '浏览量']
        },
        xAxis: {
          type: 'category',
          data: data.dates
        },
        yAxis: [
          {
            type: 'value',
            name: '销量/浏览量',
            position: 'left'
          },
          {
            type: 'value',
            name: '销售额(元)',
            position: 'right',
            axisLabel: {
              formatter: '{value} 元'
            }
          }
        ],
        series: [
          {
            name: '销量',
            type: 'bar',
            data: data.quantities
          },
          {
            name: '销售额',
            type: 'line',
            yAxisIndex: 1,
            data: data.amounts
          },
          {
            name: '浏览量',
            type: 'line',
            data: data.views
          }
        ]
      }
      
      this.productDetailChart.setOption(option)
    },
    switchTopProductsType(type) {
      this.topProductsType = type
      this.fetchData()
    },
    handleSearch() {
      this.pagination.currentPage = 1
      this.fetchData()
    },
    handleSort(value) {
      this.sortBy = value
      this.fetchData()
    },
    handleSizeChange(val) {
      this.pagination.pageSize = val
      this.fetchData()
    },
    handleCurrentChange(val) {
      this.pagination.currentPage = val
      this.fetchData()
    },
    async viewProductDetails(id) {
      try {
        const response = await statisticsApi.getProductRanking({ 
          startDate: this.filterForm.dateRange[0],
          endDate: this.filterForm.dateRange[1],
          productId: id
        })
        
        if (response.code === 0 && response.data) {
          this.currentProduct = response.data.basicInfo
          this.currentProduct.reviews = response.data.reviews
          
          this.dialogVisible = true
          
          // 等待DOM更新后初始化图表
          this.$nextTick(() => {
            this.initProductDetailChart(response.data.trends)
          })
        } else {
          this.$message.error(response.message || '获取商品详情失败')
        }
      } catch (error) {
        console.error('获取商品详情出错:', error)
        this.$message.error('获取商品详情出错')
      }
    },
    goToProductEdit() {
      this.$router.push(`/product/edit/${this.currentProduct.id}`)
    },
    resizeCharts() {
      if (this.topProductsChart) {
        this.topProductsChart.resize()
      }
      if (this.categorySalesChart) {
        this.categorySalesChart.resize()
      }
      if (this.productDetailChart && this.dialogVisible) {
        this.productDetailChart.resize()
      }
    },
    disposeCharts() {
      if (this.topProductsChart) {
        this.topProductsChart.dispose()
        this.topProductsChart = null
      }
      if (this.categorySalesChart) {
        this.categorySalesChart.dispose()
        this.categorySalesChart = null
      }
      if (this.productDetailChart) {
        this.productDetailChart.dispose()
        this.productDetailChart = null
      }
    },
    exportData() {
      this.$message({
        message: '数据导出功能正在开发中...',
        type: 'warning'
      })
    }
  }
}
</script>

